def normalize_email(raw: str) -> str:
    """Pre: raw es str. Post: strip+lower con @ presente."""
    s = raw.strip().lower()
    if "@" not in s:
        raise ValueError("email sin @")
    return s
print(normalize_email("  A@B.COM "))
try:
    normalize_email("x")
except ValueError as e:
    print("err", e)

